fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 4 {
        return i64::MIN;
    }

    let mut inc = vec![1; n];
    for i in 1..n {
        if nums[i] > nums[i - 1] {
            inc[i] = inc[i - 1] + 1;
        }
    }

    let mut dec = vec![1; n];
    for i in (0..n - 1).rev() {
        if nums[i] > nums[i + 1] {
            dec[i] = dec[i + 1] + 1;
        }
    }

    let mut inc_start = vec![1; n];
    for i in (0..n - 1).rev() {
        if nums[i] < nums[i + 1] {
            inc_start[i] = inc_start[i + 1] + 1;
        }
    }

    let mut prefix_sum = vec![0; n + 1];
    for i in 0..n {
        prefix_sum[i + 1] = prefix_sum[i] + nums[i];
    }

    let mut max_sum = i64::MIN;

    for p in 0..n {
        if inc[p] >= 2 && dec[p] >= 2 {
            let q = p + dec[p] - 1;
            if q >= n {
                continue;
            }
            if inc_start[q] >= 2 {
                let l = p - inc[p] + 1;
                let r = q + inc_start[q] - 1;
                if r >= n {
                    continue;
                }
                let current_sum = prefix_sum[r + 1] - prefix_sum[l];
                if current_sum > max_sum {
                    max_sum = current_sum;
                }
            }
        }
    }

    max_sum
}
