    for i in 1..n {
        if nums[i] > nums[i-1] {
            inc[i] = inc[i-1] + 1;
        }
    }
    let mut dec = vec![1; n];
    for i in (0..n-1).rev() {
        if nums[i] > nums[i+1] {
            dec[i] = dec[i+1] + 1;
        }
